import React, { useState, useEffect } from 'react';
import {
  LineChart, Line, XAxis, YAxis, CartesianGrid, Tooltip, ResponsiveContainer, Legend, ReferenceLine,
} from 'recharts';

const API = 'http://localhost:8001';

const ENDPOINTS = ['/health', '/login', '/get-data', '/users', '/upload', '/search', '/notifications'];
const METHODS = { '/health': 'GET', '/login': 'POST', '/get-data': 'GET', '/users': 'GET', '/upload': 'POST', '/search': 'GET', '/notifications': 'GET' };

const statusStyle = (status) => {
  if (status === 'PASS') return { bg: '#14532d', color: '#4ade80', border: '#22c55e' };
  if (status === 'WARN') return { bg: '#451a03', color: '#fbbf24', border: '#f59e0b' };
  if (status === 'FAIL') return { bg: '#450a0a', color: '#f87171', border: '#ef4444' };
  return { bg: '#1e293b', color: '#94a3b8', border: '#475569' };
};

export default function App() {
  const [history, setHistory] = useState([]);
  const [selectedTest, setSelectedTest] = useState(null);
  const [config, setConfig] = useState({ endpoint: '/login', total_requests: 100, concurrency: 10 });
  const [running, setRunning] = useState(false);
  const [error, setError] = useState('');
  const [intelligence, setIntelligence] = useState(null);

  const fetchHistory = async () => {
    try {
      const res = await fetch(`${API}/api/tests/history`);
      const data = await res.json();
      setHistory(data);
    } catch (e) {
      setError('Cannot connect to Manager API. Make sure it is running on port 8001.');
    }
  };

  useEffect(() => { fetchHistory(); }, []);

  useEffect(() => {
    if (history.length > 0 && selectedTest == null) {
      setSelectedTest(history[0].test_id);
    }
  }, [history, selectedTest]);

  const fetchIntelligence = async (testId) => {
    if (!testId) {
      setIntelligence(null);
      return;
    }
    try {
      const res = await fetch(`${API}/api/tests/${testId}/intelligence`);
      if (res.ok) {
        const data = await res.json();
        setIntelligence(data);
      }
    } catch (_) {
      setIntelligence(null);
    }
  };

  useEffect(() => {
    if (selectedTest) fetchIntelligence(selectedTest);
  }, [selectedTest]);

  const runTest = async () => {
    setRunning(true);
    setError('');
    try {
      const res = await fetch(`${API}/api/tests/run`, {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({
          target_url: 'http://localhost:8000',
          endpoint: config.endpoint,
          method: METHODS[config.endpoint] || 'GET',
          total_requests: parseInt(config.total_requests),
          concurrency: parseInt(config.concurrency),
        }),
      });
      const data = await res.json();
      await fetchHistory();
      setSelectedTest(data.test_id);
      if (data.intelligence) setIntelligence(data.intelligence);
    } catch (e) {
      setError('Test failed: ' + e.message);
    }
    setRunning(false);
  };

  const downloadReport = (testId) => {
    window.open(`${API}/api/report/${testId}`, '_blank');
  };

  const chartData = history.slice(0, 15).reverse().map((t, i) => ({
    name: `#${i + 1}`,
    avg: t.avg_latency,
    p99: t.p99_latency,
    endpoint: t.endpoint_url.split('/').pop(),
  }));

  const styles = {
    app: { background: '#0f172a', minHeight: '100vh', color: '#e2e8f0', fontFamily: "'Segoe UI', sans-serif", padding: '0' },
    header: { background: '#1e293b', borderBottom: '1px solid #334155', padding: '16px 32px', display: 'flex', alignItems: 'center', gap: '12px' },
    logo: { fontSize: '1.5rem', fontWeight: 'bold', color: '#7c3aed' },
    subtitle: { color: '#94a3b8', fontSize: '0.85rem' },
    main: { padding: '24px 32px', display: 'grid', gridTemplateColumns: '340px 1fr', gap: '24px' },
    card: { background: '#1e293b', borderRadius: '12px', padding: '20px', border: '1px solid #334155' },
    label: { color: '#94a3b8', fontSize: '0.75rem', textTransform: 'uppercase', letterSpacing: '1px', marginBottom: '6px' },
    select: { width: '100%', background: '#0f172a', color: '#e2e8f0', border: '1px solid #334155', borderRadius: '8px', padding: '10px', fontSize: '0.95rem', marginBottom: '12px' },
    input: { width: '100%', background: '#0f172a', color: '#e2e8f0', border: '1px solid #334155', borderRadius: '8px', padding: '10px', fontSize: '0.95rem', marginBottom: '12px', boxSizing: 'border-box' },
    button: { width: '100%', background: running ? '#4c1d95' : '#7c3aed', color: 'white', border: 'none', borderRadius: '8px', padding: '12px', fontSize: '1rem', fontWeight: 'bold', cursor: running ? 'not-allowed' : 'pointer' },
    right: { display: 'flex', flexDirection: 'column', gap: '24px' },
    tableWrap: { overflowX: 'auto' },
    table: { width: '100%', borderCollapse: 'collapse', fontSize: '0.85rem' },
    th: { color: '#94a3b8', textAlign: 'left', padding: '10px 12px', borderBottom: '1px solid #334155', fontSize: '0.75rem', textTransform: 'uppercase' },
    td: { padding: '10px 12px', borderBottom: '1px solid #1e293b', color: '#e2e8f0' },
  };

  return (
    <div style={styles.app}>
      <div style={styles.header}>
        <div>
          <div style={styles.logo}>⚡ Performance Audit Tool</div>
          <div style={styles.subtitle}>An Intelligent Framework for Real-time Microservice Latency Analysis — Janet Priya A</div>
        </div>
      </div>

      {error && (
        <div style={{ background: '#450a0a', color: '#f87171', padding: '12px 32px', borderBottom: '1px solid #ef4444' }}>
          ⚠️ {error}
        </div>
      )}

      <div style={styles.main}>
        {/* Left Panel - Config */}
        <div>
          <div style={styles.card}>
            <h3 style={{ marginTop: 0, color: '#7c3aed' }}>🎯 Run Performance Test</h3>
            <div style={styles.label}>Target Endpoint</div>
            <select style={styles.select} value={config.endpoint} onChange={e => setConfig({ ...config, endpoint: e.target.value })}>
              {ENDPOINTS.map(ep => <option key={ep} value={ep}>{METHODS[ep]} {ep}</option>)}
            </select>
            <div style={styles.label}>Total Requests</div>
            <input style={styles.input} type="number" value={config.total_requests} onChange={e => setConfig({ ...config, total_requests: e.target.value })} min="10" max="500" />
            <div style={styles.label}>Concurrency (Simulated Users)</div>
            <input style={styles.input} type="number" value={config.concurrency} onChange={e => setConfig({ ...config, concurrency: e.target.value })} min="1" max="50" />
            <button style={styles.button} onClick={runTest} disabled={running}>
              {running ? '⏳ Running Test...' : '▶ Run Audit'}
            </button>
          </div>

          <div style={{ ...styles.card, marginTop: '20px' }}>
            <h3 style={{ marginTop: 0, color: '#7c3aed' }}>📋 SLA Thresholds</h3>
            {[['🟢 PASS', '< 200ms avg latency'], ['🟡 WARN', '200 – 500ms avg latency'], ['🔴 FAIL', '> 500ms avg latency']].map(([label, desc]) => (
              <div key={label} style={{ padding: '8px 0', borderBottom: '1px solid #334155', display: 'flex', justifyContent: 'space-between' }}>
                <span>{label}</span><span style={{ color: '#94a3b8', fontSize: '0.85rem' }}>{desc}</span>
              </div>
            ))}
          </div>
        </div>

        {/* Right Panel */}
        <div style={styles.right}>
          {/* Chart */}
          <div style={styles.card}>
            <h3 style={{ marginTop: 0, color: '#7c3aed' }}>📈 Latency vs Time (Last 15 Tests)</h3>
            <p style={{ color: '#64748b', fontSize: '0.8rem', marginTop: '-8px', marginBottom: '12px' }}>
              Yellow dashed line: linear-regression forecast of next P99 for the highlighted row’s endpoint (multivariate anomaly + trend engine).
            </p>
            {chartData.length === 0 ? (
              <div style={{ color: '#475569', textAlign: 'center', padding: '40px' }}>No test data yet. Run your first test!</div>
            ) : (
              <ResponsiveContainer width="100%" height={220}>
                <LineChart data={chartData}>
                  <CartesianGrid strokeDasharray="3 3" stroke="#334155" />
                  <XAxis dataKey="name" stroke="#475569" />
                  <YAxis stroke="#475569" unit="ms" />
                  <Tooltip contentStyle={{ background: '#1e293b', border: '1px solid #334155', borderRadius: '8px' }} labelStyle={{ color: '#94a3b8' }} />
                  <Legend />
                  <Line type="monotone" dataKey="avg" stroke="#7c3aed" strokeWidth={2} dot={{ fill: '#7c3aed' }} name="Avg Latency" />
                  <Line type="monotone" dataKey="p99" stroke="#ef4444" strokeWidth={2} dot={{ fill: '#ef4444' }} name="P99 Latency" strokeDasharray="5 5" />
                  {intelligence && intelligence.forecast && intelligence.forecast.usable && intelligence.forecast.next_p99_ms != null && (
                    <ReferenceLine
                      y={intelligence.forecast.next_p99_ms}
                      stroke="#fbbf24"
                      strokeDasharray="6 4"
                      label={{ value: 'Lin. reg. next P99', fill: '#fbbf24', fontSize: 11 }}
                    />
                  )}
                </LineChart>
              </ResponsiveContainer>
            )}
          </div>

          {intelligence && (
            <div style={styles.card}>
              <h3 style={{ marginTop: 0, color: '#7c3aed' }}>🧠 Composite Latency Intelligence</h3>
              <p style={{ color: '#94a3b8', fontSize: '0.8rem', marginTop: '-6px' }}>
                Isolation Forest on [P99, avg, tail ratio, errors, throughput, ΔP99] + robust MAD fallback · sklearn LinearRegression P99 forecast · rule-based diagnostics
              </p>
              <div style={{ display: 'flex', flexWrap: 'wrap', gap: '16px', marginTop: '12px', alignItems: 'center' }}>
                <div style={{ flex: '1 1 200px' }}>
                  <div style={{ ...styles.label, marginBottom: '4px' }}>Composite risk (0–100)</div>
                  <div style={{ background: '#0f172a', borderRadius: '8px', height: '12px', overflow: 'hidden', border: '1px solid #334155' }}>
                    <div
                      style={{
                        width: `${intelligence.composite_risk}%`,
                        height: '100%',
                        background:
                          intelligence.composite_risk >= 70
                            ? '#ef4444'
                            : intelligence.composite_risk >= 40
                              ? '#f59e0b'
                              : '#22c55e',
                        transition: 'width 0.3s ease',
                      }}
                    />
                  </div>
                  <div style={{ color: '#e2e8f0', fontSize: '1.1rem', fontWeight: 'bold', marginTop: '6px' }}>{intelligence.composite_risk}</div>
                </div>
                <div style={{ flex: '1 1 220px' }}>
                  <div style={{ ...styles.label, marginBottom: '4px' }}>Anomaly detection</div>
                  <span
                    style={{
                      display: 'inline-block',
                      padding: '6px 12px',
                      borderRadius: '8px',
                      fontWeight: 'bold',
                      fontSize: '0.85rem',
                      background: intelligence.anomaly.is_anomaly ? '#450a0a' : '#14532d',
                      color: intelligence.anomaly.is_anomaly ? '#f87171' : '#4ade80',
                      border: `1px solid ${intelligence.anomaly.is_anomaly ? '#ef4444' : '#22c55e'}`,
                    }}
                  >
                    {intelligence.anomaly.is_anomaly ? 'ANOMALOUS vs baseline' : 'NORMAL vs baseline'}
                  </span>
                  <div style={{ color: '#64748b', fontSize: '0.75rem', marginTop: '6px' }}>
                    {intelligence.anomaly.method.replace(/_/g, ' ')} · n={intelligence.anomaly.history_runs}
                    {intelligence.anomaly.score != null && ` · score ${intelligence.anomaly.score}`}
                  </div>
                </div>
                <div style={{ flex: '1 1 220px' }}>
                  <div style={{ ...styles.label, marginBottom: '4px' }}>Forecast (next run P99)</div>
                  {intelligence.forecast && intelligence.forecast.usable ? (
                    <>
                      <div style={{ color: '#fbbf24', fontSize: '1.15rem', fontWeight: 'bold' }}>
                        ~{intelligence.forecast.next_p99_ms} ms
                      </div>
                      <div style={{ color: '#64748b', fontSize: '0.75rem' }}>
                        slope {intelligence.forecast.slope_ms_per_run} ms/run · σ resid ~{intelligence.forecast.stderr_hint} ms
                      </div>
                    </>
                  ) : (
                    <div style={{ color: '#64748b', fontSize: '0.85rem' }}>Need more runs on this endpoint for regression.</div>
                  )}
                </div>
              </div>
              <div style={{ marginTop: '16px' }}>
                <div style={styles.label}>Actionable diagnostics</div>
                <ul style={{ margin: '8px 0 0', paddingLeft: '20px', color: '#cbd5e1', fontSize: '0.88rem', lineHeight: 1.6 }}>
                  {(intelligence.recommendations || []).map((line, i) => (
                    <li key={i}>{line}</li>
                  ))}
                </ul>
              </div>
            </div>
          )}

          {/* History Table */}
          <div style={styles.card}>
            <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: '12px' }}>
              <h3 style={{ margin: 0, color: '#7c3aed' }}>🗂 Test History</h3>
              <button onClick={fetchHistory} style={{ background: '#334155', color: '#94a3b8', border: 'none', borderRadius: '6px', padding: '6px 12px', cursor: 'pointer', fontSize: '0.8rem' }}>
                ↻ Refresh
              </button>
            </div>
            {history.length === 0 ? (
              <div style={{ color: '#475569', textAlign: 'center', padding: '32px' }}>No tests run yet.</div>
            ) : (
              <div style={styles.tableWrap}>
                <table style={styles.table}>
                  <thead>
                    <tr>
                      <th style={styles.th}>Endpoint</th>
                      <th style={styles.th}>Requests</th>
                      <th style={styles.th}>Avg Latency</th>
                      <th style={styles.th}>P99</th>
                      <th style={styles.th}>Success</th>
                      <th style={styles.th}>RPS</th>
                      <th style={styles.th}>Status</th>
                      <th style={styles.th}>Report</th>
                    </tr>
                  </thead>
                  <tbody>
                    {history.map(test => {
                      const s = statusStyle(test.status);
                      const isSelected = test.test_id === selectedTest;
                      return (
                        <tr
                          key={test.test_id}
                          onClick={() => setSelectedTest(test.test_id)}
                          style={{
                            background: isSelected ? '#1e3a5f' : 'transparent',
                            cursor: 'pointer',
                          }}
                        >
                          <td style={styles.td}><span style={{ color: '#7c3aed' }}>{test.method}</span> {test.endpoint_url.replace('http://localhost:8000', '')}</td>
                          <td style={styles.td}>{test.total_requests}</td>
                          <td style={styles.td}>{test.avg_latency} ms</td>
                          <td style={styles.td}>{test.p99_latency} ms</td>
                          <td style={styles.td} ><span style={{ color: '#4ade80' }}>{test.success_rate}%</span></td>
                          <td style={styles.td}>{test.throughput_rps}</td>
                          <td style={styles.td}>
                            <span style={{ background: s.bg, color: s.color, border: `1px solid ${s.border}`, padding: '3px 10px', borderRadius: '20px', fontSize: '0.75rem', fontWeight: 'bold' }}>
                              {test.status}
                            </span>
                          </td>
                          <td style={styles.td}>
                            <button
                              onClick={(e) => {
                                e.stopPropagation();
                                downloadReport(test.test_id);
                              }}
                              style={{ background: '#1e293b', color: '#7c3aed', border: '1px solid #7c3aed', borderRadius: '6px', padding: '4px 10px', cursor: 'pointer', fontSize: '0.75rem' }}
                            >
                              ↓ Report
                            </button>
                          </td>
                        </tr>
                      );
                    })}
                  </tbody>
                </table>
              </div>
            )}
          </div>
        </div>
      </div>
    </div>
  );
}
